function ProgressBar({filled,slots,color}){
  const pct=Math.round((filled/slots)*100);
  const full=filled>=slots;
  return(
    <div style={{marginTop:"10px"}}>
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:"5px"}}>
        <span style={{fontFamily:"'DM Sans',sans-serif",fontSize:"11px",color:"rgba(255,255,255,0.3)"}}>{filled}/{slots} slots</span>
        <span style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"11px",letterSpacing:"2px",color:full?C.pink:color}}>{full?"FULL":`${slots-filled} LEFT`}</span>
      </div>
      <div style={{height:"3px",background:"rgba(255,255,255,0.07)",borderRadius:"2px",overflow:"hidden"}}>
        <div style={{height:"100%",width:`${pct}%`,background:full?C.pink:color,borderRadius:"2px",transition:"width .6s ease"}}/>
      </div>
    </div>
  );
}
