// 404 PAGE
// ══════════════════════════════════════════════════════════════════════════════
function NotFoundPage({setPage}){
  return(
    <div style={{background:C.bg,color:C.white,minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",position:"relative",overflow:"hidden",padding:"120px 24px"}}>
      <Orb top="10%" left="-5%" size={500} opacity={0.1}/>
      <Orb bottom="10%" right="-5%" size={400} color={C.pink} opacity={0.08} delay="2s"/>
      <div style={{position:"relative",zIndex:2,textAlign:"center",maxWidth:"600px"}}>
        <div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"clamp(80px,15vw,160px)",lineHeight:1,color:"rgba(255,107,0,0.12)",marginBottom:"-20px",WebkitTextStroke:"2px rgba(255,107,0,0.3)"}}>404</div>
        <h1 style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"clamp(32px,5vw,56px)",color:C.white,lineHeight:1,marginBottom:"20px"}}>This vibe<br/><span style={{color:C.orange}}>doesn't exist.</span></h1>
        <p style={{fontFamily:"'DM Sans',sans-serif",fontSize:"17px",color:C.dim,lineHeight:1.7,marginBottom:"40px"}}>The page you're looking for has either moved, been deleted, or never existed in the first place.</p>
        <div style={{display:"flex",gap:"14px",justifyContent:"center",flexWrap:"wrap"}}>
          <button onClick={()=>{setPage("home");window.scrollTo(0,0);}} style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"15px",letterSpacing:"3px",padding:"14px 36px",background:C.orange,color:C.bg,border:"none",borderRadius:"2px",cursor:"pointer",transition:"transform .2s,box-shadow .2s"}} onMouseEnter={e=>{e.target.style.transform="translateY(-2px)";e.target.style.boxShadow=`0 12px 32px ${C.orange}40`;}} onMouseLeave={e=>{e.target.style.transform="";e.target.style.boxShadow="";}}>Back to Home</button>
          <button onClick={()=>{setPage("Contact");window.scrollTo(0,0);}} style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"15px",letterSpacing:"3px",padding:"14px 36px",background:"transparent",color:C.white,border:"1px solid rgba(255,255,255,0.2)",borderRadius:"2px",cursor:"pointer",transition:"all .2s"}} onMouseEnter={e=>{e.currentTarget.style.borderColor=C.orange;e.currentTarget.style.color=C.orange;}} onMouseLeave={e=>{e.currentTarget.style.borderColor="rgba(255,255,255,0.2)";e.currentTarget.style.color=C.white;}}>Report an Issue</button>
        </div>
      </div>
    </div>
  );
}

