// ROOT APP
// ══════════════════════════════════════════════════════════════════════════════
export default function App(){
  const [page,setPage]=useState("home");

  const PageMap={
    home:     <HomePage setPage={setPage}/>,
    About:    <AboutPage/>,
    Team:     <TeamPage/>,
    Creators: <CreatorsPage setPage={setPage}/>,
    Advertise:<AdvertisePage/>,
    Business: <BusinessPage/>,
    Jobs:     <JobsPage/>,
    Marketplace:<MarketplacePage/>,
    Contact:  <ContactPage/>,
  };

  const content=PageMap[page]||<NotFoundPage setPage={setPage}/>;

  return(
    <>
      <style>{GLOBAL_CSS}</style>
      <Nav current={page} setPage={setPage}/>
      <main>{content}</main>
      <Footer setPage={setPage}/>
    </>
  );
}
